var createProviderProfile = async (data, userId) => {
  const result = await prisma.provider_Profile.create({
    data: {
      ...data,
      user_id: userId,
      // <-- only use user_id, DO NOT include `user` object
      image: data.image || null
    }
  });
  return result;
};
var getProviderProfile = async () => {
  const Profile = await prisma.provider_Profile.findFirst();
  return Profile;
};
var getAllSystemStatsForAdmin = async () => {
  const providers = await prisma.provider_Profile.findMany({
    include: {
      _count: {
        select: { meals: true }
      },
      meals: {
        include: {
          orderItems: {
            include: {
              orders: true
            }
          },
          category: true
          // ক্যাটাগরি নাম দেখানোর জন্য
        }
      }
    }
  });
  return providers.map((p) => {
    let totalRevenue = 0;
    let activeOrdersCount = 0;
    let totalOrdersCount = 0;
    p.meals.forEach((meal) => {
      meal.orderItems.forEach((item) => {
        if (item.orders) {
          totalOrdersCount++;
          if (["PLACED", "PREPARING", "READY"].includes(item.orders.status)) {
            activeOrdersCount++;
          }
          if (item.orders.status === "DELIVERED") {
            totalRevenue += Number(item.price_at_order) * item.quantity;
          }
        }
      });
    });
    return {
      id: p.id,
      restaurantName: p.restaurant_name,
      address: p.address,
      totalMeals: p._count.meals,
      totalOrders: totalOrdersCount,
      activeOrders: activeOrdersCount,
      totalRevenue,
      // প্রতিটি খাবারের ডিটেইলস এবং স্ট্যাটাস এখানে আসবে
      meals: p.meals.map((m) => ({
        id: m.id,
        name: m.name,
        price: Number(m.price),
        status: m.status,
        // AVAILABLE or UNAVAILABLE
        category: m.category.name,
        image: m.image_url
      }))
    };
  });
};
var updateProviderStatus = async (id, is_active) => {
  return await prisma.provider_Profile.update({
    where: { id },
    data: { is_active }
  });
};
