// src/middlewares/auth.ts
var auth2 = (...roles) => {
  return async (req, res, next) => {
    try {
      const session = await auth.api.getSession({
        headers: { cookie: req.headers.cookie || "" }
      });
      console.log("HEADERS \u{1F449}", req.headers);
      console.log("COOKIE \u{1F449}", req.headers.cookie);
      console.log("SESSION \u{1F449}", session);
      console.log("SESSION USER \u{1F449}", session?.user);
      if (!session) {
        return res.status(401).json({
          success: false,
          message: "You are not authorised"
        });
      }
      if (!session.user.emailVerified) {
        return res.status(403).json({
          success: false,
          message: "Email verification requiered ,plz verify your email "
        });
      }
      req.user = {
        id: session.user.id,
        email: session.user.email,
        name: session.user.name,
        role: session.user.role,
        emailVerified: session.user.emailVerified
      };
      if (roles.length && !roles.includes(req.user.role)) {
        return res.status(403).json({
          success: false,
          message: "forbidden ! You don't have a permission to access this resourcess !"
        });
      }
      next();
    } catch (err) {
      next(err);
    }
  };
};
