// src/modules/provider-order/providerOrder.service.ts
var getProviderOrders = async (userId) => {
  const provider = await prisma.provider_Profile.findUnique({
    where: { user_id: userId }
  });
  if (!provider) {
    throw new Error("Provider profile not found");
  }
  const orderItems = await prisma.order_items.findMany({
    where: {
      meal: {
        provider_id: provider.id
      }
    },
    include: {
      orders: true,
      meal: {
        select: {
          name: true,
          price: true
        }
      },
      customer: {
        select: {
          name: true,
          email: true
        }
      }
    }
  });
  return orderItems;
};
var allowedStatusFlow = {
  PLACED: [OrderStatus.PREPARING],
  PREPARING: [OrderStatus.READY]
};
var updateOrderStatus = async (providerUserId, orderId, newStatus) => {
  const provider = await prisma.provider_Profile.findUnique({
    where: { user_id: providerUserId }
  });
  if (!provider) {
    throw new Error("Provider profile not found");
  }
  const order = await prisma.orders.findUnique({
    where: { id: orderId },
    include: {
      orderItems: {
        include: {
          meal: true
        }
      }
    }
  });
  if (!order) {
    throw new Error("Order not found");
  }
  const isProviderOrder = order.orderItems.some(
    (item) => item.meal.provider_id === provider.id
  );
  if (order.status === OrderStatus.READY) {
    throw new Error("Order already completed");
  }
  if (!isProviderOrder) {
    throw new Error("You are not allowed to update this order");
  }
  const allowedNext = allowedStatusFlow[order.status];
  if (!allowedNext || !allowedNext.includes(newStatus)) {
    throw new Error(
      `Invalid status transition from ${order.status} to ${newStatus}`
    );
  }
  const updatedOrder = await prisma.orders.update({
    where: { id: orderId },
    data: { status: newStatus }
  });
  return updatedOrder;
};
var ProviderOrderService = {
  getProviderOrders,
  updateOrderStatus
};

