var getDashboardStats = async () => {
  const [
    totalUsers,
    totalProviders,
    totalMeals,
    totalOrders,
    revenue,
    orderStats
  ] = await Promise.all([
    prisma.user.count(),
    prisma.provider_Profile.count(),
    prisma.meals.count(),
    prisma.orders.count(),
    prisma.orders.aggregate({
      _sum: {
        total_price: true
      }
    }),
    prisma.orders.groupBy({
      by: ["status"],
      _count: {
        _all: true
      }
    })
  ]);
  return {
    totalUsers,
    totalProviders,
    totalMeals,
    totalOrders,
    totalRevenue: revenue._sum.total_price || 0,
    ordersByStatus: orderStats
  };
};
