// src/modules/reviews/reviews.route.ts
import express8 from "express";

// src/modules/reviews/reviews.service.ts
var createReview = async (userId, mealId, data) => {
  const existing = await prisma.reviews.findFirst({
    where: {
      customer_id: userId,
      meal_id: mealId
    }
  });
  if (existing) {
    throw new Error("You have already reviewed this meal");
  }
  const review = await prisma.reviews.create({
    data: {
      customer_id: userId,
      meal_id: mealId,
      rating: data.rating,
      comment: data.comment
    }
  });
  return review;
};
var getReviewsByMeal = async (mealId) => {
  const reviews = await prisma.reviews.findMany({
    where: { meal_id: mealId },
    include: {
      customer: {
        select: {
          name: true,
          email: true
        }
      }
    }
  });
  return reviews;
};
var getReviewsProviderByMeal = async (mealId, providerId) => {
  const meal = await prisma.meals.findUnique({
    where: { id: mealId },
    select: { provider_id: true }
  });
  if (!meal) throw new Error("Meal not found");
  if (meal.provider_id !== providerId) throw new Error("Not authorized to view reviews");
  const reviews = await prisma.reviews.findMany({
    where: { meal_id: mealId },
    include: {
      customer: { select: { name: true, email: true } }
    },
    orderBy: { created_at: "desc" }
  });
  return reviews;
};
var getAllReviewsbyAdmin = async () => {
  const reviews = await prisma.reviews.findMany({
    include: {
      customer: { select: { name: true, email: true } },
      meal: { select: { name: true, provider_id: true } }
    },
    orderBy: { created_at: "desc" }
  });
  return reviews;
};
var deleteReviewbyAdmin = async (reviewId) => {
  return await prisma.reviews.delete({
    where: { id: reviewId }
  });
};
var ReviewsService = {
  createReview,
  getReviewsByMeal,
  getReviewsProviderByMeal,
  getAllReviewsbyAdmin,
  deleteReviewbyAdmin
};

